from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression is invalid."""


@dataclass(frozen=True)
class FieldDefinition:
    name: str
    minimum: int
    maximum: int


@dataclass(frozen=True)
class CronField:
    definition: FieldDefinition
    raw: str
    values: tuple[int, ...]

    @property
    def name(self) -> str:
        return self.definition.name

    @property
    def minimum(self) -> int:
        return self.definition.minimum

    @property
    def maximum(self) -> int:
        return self.definition.maximum

    @property
    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.minimum, self.maximum + 1))

    @property
    def single_value(self) -> int | None:
        return self.values[0] if len(self.values) == 1 else None


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        if all(field.is_wildcard for field in self.fields):
            return "Every minute"

        if self._is_every_n_minutes():
            return f"Every {self._step_size(self.minute.raw)} minutes"

        if self._is_every_n_hours_on_the_hour():
            return f"Every {self._step_size(self.hour.raw)} hours, on the hour"

        time_text = self._describe_time()
        date_parts = self._describe_date_parts()

        if not date_parts:
            return time_text

        return f"{time_text} {' '.join(date_parts)}"

    @property
    def fields(self) -> tuple[CronField, CronField, CronField, CronField, CronField]:
        return (
            self.minute,
            self.hour,
            self.day_of_month,
            self.month,
            self.day_of_week,
        )

    def _is_every_n_minutes(self) -> bool:
        return (
            self.minute.raw.startswith("*/")
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _is_every_n_hours_on_the_hour(self) -> bool:
        return (
            self.minute.single_value == 0
            and self.hour.raw.startswith("*/")
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _describe_time(self) -> str:
        minute = self.minute.single_value
        hour = self.hour.single_value

        if minute is None or hour is None:
            return self._describe_general_time()

        if hour == 0 and minute == 0:
            return "At midnight"

        return f"At {hour:02d}:{minute:02d}"

    def _describe_general_time(self) -> str:
        if self.minute.single_value == 0 and not self.hour.is_wildcard:
            return f"On the hour during {describe_values(self.hour.values)}"

        if self.hour.is_wildcard and self.minute.single_value is not None:
            return f"At minute {self.minute.single_value} of every hour"

        return (
            f"At minute {describe_values(self.minute.values)} "
            f"during hour {describe_values(self.hour.values)}"
        )

    def _describe_date_parts(self) -> list[str]:
        parts: list[str] = []

        if not self.day_of_month.is_wildcard:
