MINUTE = FieldDefinition("minute", 0, 59)
HOUR = FieldDefinition("hour", 0, 23)
DAY_OF_MONTH = FieldDefinition("day_of_month", 1, 31)
MONTH = FieldDefinition("month", 1, 12)
DAY_OF_WEEK = FieldDefinition("day_of_week", 0, 6)

FIELD_DEFINITIONS = (MINUTE, HOUR, DAY_OF_MONTH, MONTH, DAY_OF_WEEK)

