def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise CronParseError(
            f"Expected 5 cron fields, got {len(parts)} in {expression!r}"
        )

    parsed_fields = [
        parse_field(raw, definition)
        for raw, definition in zip(parts, FIELD_DEFINITIONS, strict=True)
    ]

    return CronSchedule(
        minute=parsed_fields[0],
        hour=parsed_fields[1],
        day_of_month=parsed_fields[2],
        month=parsed_fields[3],
        day_of_week=parsed_fields[4],
    )


def parse_field(raw: str, definition: FieldDefinition) -> CronField:
    if not raw:
        raise CronParseError(f"{definition.name} field cannot be empty")

    values: set[int] = set()

    for item in raw.split(","):
        if not item:
            raise CronParseError(f"Empty list item in {definition.name} field: {raw!r}")

        values.update(parse_field_item(item, definition))

    return CronField(
        definition=definition,
        raw=raw,
        values=tuple(sorted(values)),
    )


def parse_field_item(item: str, definition: FieldDefinition) -> set[int]:
    base, step = split_step(item, definition)

    if base == "*":
        start = definition.minimum
        end = definition.maximum
    elif "-" in base:
        start, end = parse_range(base, definition)
    else:
        start = end = parse_integer(base, definition)

    validate_bounds(start, end, definition)

    if step is None:
        return set(range(start, end + 1))

    return set(range(start, end + 1, step))


def split_step(item: str, definition: FieldDefinition) -> tuple[str, int | None]:
    if "/" not in item:
        return item, None

    pieces = item.split("/")

    if len(pieces) != 2:
        raise CronParseError(f"Invalid step syntax in {definition.name} field: {item!r}")

    base, step_text = pieces

    if not base or not step_text:
        raise CronParseError(f"Invalid step syntax in {definition.name} field: {item!r}")

    step = parse_integer(step_text, definition)

    if step <= 0:
        raise CronParseError(f"Step must be greater than zero in {definition.name}: {item!r}")

    return base, step


def parse_range(text: str, definition: FieldDefinition) -> tuple[int, int]:
    pieces = text.split("-")

    if len(pieces) != 2:
        raise CronParseError(f"Invalid range in {definition.name} field: {text!r}")

    start = parse_integer(pieces[0], definition)
    end = parse_integer(pieces[1], definition)

    if start > end:
        raise CronParseError(
            f"Range start must be <= range end in {definition.name}: {text!r}"
        )

    return start, end


def parse_integer(text: str, definition: FieldDefinition) -> int:
    if not text.isdigit():
        raise CronParseError(
            f"Expected a number in {definition.name} field, got {text!r}"
        )

    value = int(text)
    validate_value(value, definition)
    return value


def validate_bounds(start: int, end: int, definition: FieldDefinition) -> None:
    validate_value(start, definition)
    validate_value(end, definition)


def validate_value(value: int, definition: FieldDefinition) -> None:
    if not definition.minimum <= value <= definition.maximum:
        raise CronParseError(
            f"{definition.name} value {value} is outside allowed range "
            f"{definition.minimum}-{definition.maximum}"
        )


def describe_values(values: Iterable[int]) -> str:
    return join_english([str(value) for value in values])


def describe_weekdays(values: Iterable[int]) -> str:
    ordered = list(values)

    if is_contiguous(ordered):
        return f"{WEEKDAY_NAMES[ordered[0]]} through {WEEKDAY_NAMES[ordered[-1]]}"

    return join_english([WEEKDAY_NAMES[value] for value in ordered])


def describe_months(values: Iterable[int]) -> str:
    ordered = list(values)

    if is_contiguous(ordered):
        return f"{MONTH_NAMES[ordered[0]]} through {MONTH_NAMES[ordered[-1]]}"

    return join_english([MONTH_NAMES[value] for value in ordered])


def describe_ordinals(values: Iterable[int]) -> str:
    return join_english([ordinal(value) for value in values])


def is_contiguous(values: list[int]) -> bool:
    return bool(values) and values == list(range(values[0], values[-1] + 1))


def join_english(items: list[str]) -> str:
    if not items:
        return ""

    if len(items) == 1:
        return items[0]

    if len(items) == 2:
        return f"{items[0]} and {items[1]}"

    return f"{', '.join(items[:-1])}, and {items[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


